import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { trafficAPI } from '../services/api';
import { Car, LogOut, Activity, Clock } from 'lucide-react';

function Dashboard() {
    const [trafficData, setTrafficData] = useState([]);
    const [currentCount, setCurrentCount] = useState(0);
    const [signalState, setSignalState] = useState('RED');
    const navigate = useNavigate();

    // Fetch data every 3 seconds
    useEffect(() => {
        const fetchData = async () => {
            try {
                // Fetch the latest status decided by Java Logic
                const response = await trafficAPI.getHistory(); 
                // Note: We are still using history for now, but grabbing the last item
                // In Step 7 we will optimize this to use /latest-status
                const data = response.data;
                setTrafficData(data);
                
                if (data.length > 0) {
                    const latest = data[data.length - 1];
                    setCurrentCount(latest.vehicleCount);
                    
                    // Use the Signal State decided by Java
                    setSignalState(latest.signalState.includes("GREEN") ? "GREEN" : "RED");
                }
            } catch (err) {
                console.error('Error fetching data:', err);
            }
        };
        fetchData();
        const interval = setInterval(fetchData, 3000);
        return () => clearInterval(interval);
    }, []);

    const handleLogout = () => {
        localStorage.removeItem('user');
        navigate('/');
    };

    return (
        <div style={styles.container}>
            {/* Header */}
            <div style={styles.header}>
                <div style={styles.logo}>
                    <Car size={32} color="#4CAF50" />
                    <h1 style={styles.headerTitle}>Smart Traffic Dashboard</h1>
                </div>
                <button onClick={handleLogout} style={styles.logoutBtn}>
                    <LogOut size={20} />
                    Logout
                </button>
            </div>

            {/* Main Content */}
            <div style={styles.content}>
                {/* Signal Status Card */}
                <div style={{
                    ...styles.card,
                    background: signalState === 'GREEN' ? '#4CAF50' : '#f44336'
                }}>
                    <h3 style={styles.cardTitle}>Current Signal</h3>
                    <div style={styles.signalLight}>
                        <div style={{
                            ...styles.light,
                            opacity: signalState === 'GREEN' ? 1 : 0.3
                        }}></div>
                        <div style={{
                            ...styles.light,
                            opacity: signalState === 'RED' ? 1 : 0.3
                        }}></div>
                    </div>
                    <h2 style={styles.signalText}>{signalState}</h2>
                </div>
                
                {/* Video Feed Card */}
                <div style={{...styles.card, gridColumn: 'span 3'}}>
                    <h3 style={styles.cardTitle}>
                        📹 Live Traffic Feed
                    </h3>
                    <div style={styles.videoContainer}>
                        <img 
                            src="http://localhost:5000/video_feed" 
                            alt="Traffic Feed"
                            style={styles.videoFeed}
                        />
                    </div>
                    <p style={styles.videoNote}>
                        🎯 AI Detection Active | Real-time Vehicle Counting
                    </p>
                </div>

                {/* Vehicle Count Card */}
                <div style={styles.card}>
                    <h3 style={styles.cardTitle}>
                        <Activity size={20} style={{marginRight: 8}} />
                        Vehicles Detected
                    </h3>
                    <p style={styles.bigNumber}>{currentCount}</p>
                    <p style={styles.cardSubtitle}>Lane: NORTH</p>
                </div>

                {/* Wait Time Card */}
                <div style={styles.card}>
                    <h3 style={styles.cardTitle}>
                        <Clock size={20} style={{marginRight: 8}} />
                        System Status
                    </h3>
                    <p style={styles.status}>🟢 AI Service Connected</p>
                    <p style={styles.status}>🟢 Backend Running</p>
                    <p style={styles.status}>🟢 Database Active</p>
                </div>
            </div>

            {/* Traffic History Table */}
            <div style={styles.tableContainer}>
                <h3 style={styles.tableTitle}>Recent Traffic Logs</h3>
                <table style={styles.table}>
                    <thead>
                        <tr>
                            <th style={styles.th}>Time</th>
                            <th style={styles.th}>Lane</th>
                            <th style={styles.th}>Vehicles</th>
                            <th style={styles.th}>Signal</th>
                        </tr>
                    </thead>
                    <tbody>
                        {trafficData.slice(-5).reverse().map((log, index) => (
                            <tr key={index} style={styles.tr}>
                                <td style={styles.td}>{new Date(log.timestamp).toLocaleTimeString()}</td>
                                <td style={styles.td}>{log.laneId}</td>
                                <td style={styles.td}>{log.vehicleCount}</td>
                                <td style={styles.td}>{log.signalState}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    );
}

const styles = {
    container: {
        minHeight: '100vh',
        background: 'linear-gradient(135deg, #0f0f23 0%, #1a1a3a 100%)',
        color: '#fff',
        fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif",
    },
    header: {
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        padding: '20px 40px',
        background: 'rgba(255,255,255,0.1)',
        backdropFilter: 'blur(10px)',
        borderBottom: '1px solid rgba(255,255,255,0.1)',
    },
    logo: {
        display: 'flex',
        alignItems: 'center',
        gap: '12px',
    },
    headerTitle: {
        margin: 0,
        color: '#fff',
        fontSize: '24px',
        fontWeight: '600',
    },
    logoutBtn: {
        display: 'flex',
        alignItems: 'center',
        gap: '8px',
        padding: '10px 20px',
        background: 'linear-gradient(135deg, #ff6b6b, #ee5a5a)',
        color: 'white',
        border: 'none',
        borderRadius: '8px',
        cursor: 'pointer',
        fontSize: '14px',
        fontWeight: '500',
        transition: 'transform 0.2s',
    },
    content: {
        display: 'grid',
        gridTemplateColumns: 'repeat(3, 1fr)',
        gap: '24px',
        padding: '40px',
    },
    card: {
        background: 'rgba(255,255,255,0.08)',
        backdropFilter: 'blur(10px)',
        padding: '24px',
        borderRadius: '16px',
        border: '1px solid rgba(255,255,255,0.1)',
        boxShadow: '0 8px 32px rgba(0,0,0,0.3)',
    },
    cardTitle: {
        margin: '0 0 16px 0',
        color: '#aaa',
        display: 'flex',
        alignItems: 'center',
        fontSize: '14px',
        fontWeight: '500',
        textTransform: 'uppercase',
        letterSpacing: '0.5px',
    },
    bigNumber: {
        fontSize: '56px',
        fontWeight: 'bold',
        color: '#fff',
        margin: '8px 0',
        textShadow: '0 0 20px rgba(76, 175, 80, 0.5)',
    },
    cardSubtitle: {
        color: '#888',
        margin: '8px 0 0 0',
        fontSize: '14px',
    },
    signalLight: {
        display: 'flex',
        gap: '16px',
        justifyContent: 'center',
        margin: '24px 0',
    },
    light: {
        width: '70px',
        height: '70px',
        borderRadius: '50%',
        background: '#333',
        border: '3px solid #555',
        transition: 'all 0.3s ease',
    },
    signalText: {
        textAlign: 'center',
